# Generated by anthropic (claude-opus-4-6)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(
            name: 'ARTIFACT_URLS',
            defaultValue: '',
            description: 'Comma-separated list of artifact URLs to download (supports S3, Artifactory, HTTP/HTTPS)'
        )
        string(
            name: 'DEPLOY_SERVERS',
            defaultValue: '',
            description: 'Comma-separated list of production server hostnames/IPs to deploy to'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/app/deploy',
            description: 'Target deployment path on production servers'
        )
        string(
            name: 'DEPLOY_USER',
            defaultValue: 'deploy',
            description: 'SSH user for deployment to production servers'
        )
        credentials(
            name: 'SSH_CREDENTIAL_ID',
            defaultValue: '',
            description: 'SSH credentials for connecting to production servers',
            credentialType: 'com.cloudbees.jenkins.plugins.sshcredentials.impl.BasicSSHUserPrivateKey'
        )
        credentials(
            name: 'ARTIFACTORY_CREDENTIAL_ID',
            defaultValue: '',
            description: 'Credentials for Artifactory authentication (optional)',
            credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordCredentialsImpl'
        )
        credentials(
            name: 'AWS_CREDENTIAL_ID',
            defaultValue: '',
            description: 'AWS credentials for S3 access (optional)',
            credentialType: 'com.cloudbees.jenkins.plugins.awscredentials.AWSCredentialsImpl'
        )
        string(
            name: 'PRE_DEPLOY_SCRIPT',
            defaultValue: '',
            description: 'Optional script to run on each server before deployment (e.g., stop services)'
        )
        string(
            name: 'POST_DEPLOY_SCRIPT',
            defaultValue: '',
            description: 'Optional script to run on each server after deployment (e.g., start services)'
        )
        string(
            name: 'HEALTH_CHECK_URL_PATTERN',
            defaultValue: '',
            description: 'Health check URL pattern. Use {SERVER} as placeholder (e.g., http://{SERVER}:8080/health)'
        )
        string(
            name: 'HEALTH_CHECK_TIMEOUT',
            defaultValue: '120',
            description: 'Health check timeout in seconds'
        )
        booleanParam(
            name: 'ROLLING_DEPLOY',
            defaultValue: true,
            description: 'Deploy to servers one at a time (rolling) vs all at once'
        )
        booleanParam(
            name: 'DRY_RUN',
            defaultValue: false,
            description: 'Perform a dry run without actual deployment'
        )
        booleanParam(
            name: 'BACKUP_EXISTING',
            defaultValue: true,
            description: 'Backup existing artifacts on production servers before deploying'
        )
    }

    environment {
        ARTIFACTS_DIR = "${WORKSPACE}/artifacts"
        CHECKSUM_FILE = "${WORKSPACE}/artifacts/checksums.sha256"
        TIMESTAMP = sh(script: 'date +%Y%m%d_%H%M%S', returnStdout: true).trim()
    }

    options {
        timeout(time: 60, unit: 'MINUTES')
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '30'))
        disableConcurrentBuilds()
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    echo "=== Validating Pipeline Parameters ==="

                    if (!params.ARTIFACT_URLS?.trim()) {
                        error "ARTIFACT_URLS parameter is required. Provide comma-separated URLs."
                    }
                    if (!params.DEPLOY_SERVERS?.trim()) {
                        error "DEPLOY_SERVERS parameter is required. Provide comma-separated server addresses."
                    }
                    if (!params.DEPLOY_PATH?.trim()) {
                        error "DEPLOY_PATH parameter is required."
                    }
                    if (!params.SSH_CREDENTIAL_ID?.trim()) {
                        error "SSH_CREDENTIAL_ID is required for deployment."
                    }

                    env.ARTIFACT_URL_LIST = params.ARTIFACT_URLS.trim()
                    env.SERVER_LIST = params.DEPLOY_SERVERS.trim()

                    def urls = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }

                    echo "Artifacts to download (${urls.size()}):"
                    urls.eachWithIndex { url, idx ->
                        echo "  ${idx + 1}. ${url}"
                    }

                    echo "Target servers (${servers.size()}):"
                    servers.eachWithIndex { server, idx ->
                        echo "  ${idx + 1}. ${server}"
                    }

                    echo "Deploy path: ${params.DEPLOY_PATH}"
                    echo "Deploy user: ${params.DEPLOY_USER}"
                    echo "Rolling deploy: ${params.ROLLING_DEPLOY}"
                    echo "Dry run: ${params.DRY_RUN}"
                    echo "Backup existing: ${params.BACKUP_EXISTING}"

                    if (params.DRY_RUN) {
                        echo "*** DRY RUN MODE - No actual deployment will occur ***"
                    }
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                script {
                    echo "=== Preparing Workspace ==="
                    sh """
                        rm -rf ${ARTIFACTS_DIR}
                        mkdir -p ${ARTIFACTS_DIR}
                    """
                }
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    echo "=== Downloading Artifacts ==="
                    def urls = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }
                    def downloadResults = [:]

                    for (url in urls) {
                        def filename = extractFilename(url)
                        def targetPath = "${ARTIFACTS_DIR}/${filename}"

                        echo "Downloading: ${url}"
                        echo "  -> ${targetPath}"

                        try {
                            if (url.startsWith('s3://')) {
                                downloadFromS3(url, targetPath)
                            } else if (isArtifactoryUrl(url)) {
                                downloadFromArtifactory(url, targetPath)
                            } else if (url.startsWith('http://') || url.startsWith('https://')) {
                                downloadFromHttp(url, targetPath)
                            } else {
                                error "Unsupported URL scheme: ${url}"
                            }

                            // Verify download
                            def fileExists = sh(script: "test -f '${targetPath}' && echo 'true' || echo 'false'", returnStdout: true).trim()
                            if (fileExists != 'true') {
                                error "Downloaded file not found at ${targetPath}"
                            }

                            def fileSize = sh(script: "stat -c%s '${targetPath}' 2>/dev/null || stat -f%z '${targetPath}' 2>/dev/null", returnStdout: true).trim()
                            echo "  Downloaded successfully (${formatFileSize(fileSize.toLong())})"

                            downloadResults[filename] = [
                                url: url,
                                path: targetPath,
                                size: fileSize,
                                status: 'SUCCESS'
                            ]
                        } catch (Exception e) {
                            echo "  FAILED: ${e.message}"
                            downloadResults[filename] = [
                                url: url,
                                path: targetPath,
                                status: 'FAILED',
                                error: e.message
                            ]
                            error "Failed to download artifact from ${url}: ${e.message}"
                        }
                    }

                    // Generate checksums
                    sh """
                        cd ${ARTIFACTS_DIR}
                        sha256sum * > checksums.sha256 2>/dev/null || shasum -a 256 * > checksums.sha256 2>/dev/null || true
                    """

                    echo "\n=== Download Summary ==="
                    echo sh(script: "cat ${CHECKSUM_FILE}", returnStdout: true).trim()

                    echo "\n=== Downloaded Files ==="
                    sh "ls -lah ${ARTIFACTS_DIR}/"
                }
            }
        }

        stage('Verify Artifacts') {
            steps {
                script {
                    echo "=== Verifying Downloaded Artifacts ==="

                    def files = sh(
                        script: "find ${ARTIFACTS_DIR} -maxdepth 1 -type f ! -name 'checksums.sha256' -exec basename {} \\;",
                        returnStdout: true
                    ).trim().split('\n').findAll { it }

                    if (files.size() == 0) {
                        error "No artifacts found in ${ARTIFACTS_DIR}"
                    }

                    echo "Found ${files.size()} artifact(s):"
                    files.each { file ->
                        def filePath = "${ARTIFACTS_DIR}/${file}"
                        def fileSize = sh(script: "stat -c%s '${filePath}' 2>/dev/null || stat -f%z '${filePath}' 2>/dev/null", returnStdout: true).trim()

                        if (fileSize.toLong() == 0) {
                            error "Artifact ${file} is empty (0 bytes)"
                        }

                        echo "  ✓ ${file} (${formatFileSize(fileSize.toLong())})"

                        // Check if it's an archive and validate
                        if (file.endsWith('.tar.gz') || file.endsWith('.tgz')) {
                            sh "gzip -t '${filePath}'"
                            echo "    Archive integrity: OK"
                        } else if (file.endsWith('.zip')) {
                            sh "unzip -t '${filePath}' > /dev/null"
                            echo "    Archive integrity: OK"
                        } else if (file.endsWith('.jar') || file.endsWith('.war') || file.endsWith('.ear')) {
                            sh "unzip -t '${filePath}' > /dev/null"
                            echo "    Java archive integrity: OK"
                        }
                    }
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    echo "=== Deploying to Production Servers ==="

                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def deployResults = [:]

                    if (params.ROLLING_DEPLOY) {
                        echo "Using rolling deployment strategy"
                        for (server in servers) {
                            deployToServer(server, deployResults)
                        }
                    } else {
                        echo "Using parallel deployment strategy"
                        def parallelStages = [:]
                        for (srv in servers) {
                            def server = srv // capture for closure
                            parallelStages["Deploy to ${server}"] = {
                                deployToServer(server, deployResults)
                            }
                        }
                        parallel parallelStages
                    }

                    // Summary
                    echo "\n=== Deployment Summary ==="
                    def successCount = 0
                    def failCount = 0
                    deployResults.each { server, result ->
                        if (result.status == 'SUCCESS') {
                            echo "  ✓ ${server}: ${result.status}"
                            successCount++
                        } else {
                            echo "  ✗ ${server}: ${result.status} - ${result.error ?: 'Unknown error'}"
                            failCount++
                        }
                    }
                    echo "\nTotal: ${successCount} succeeded, ${failCount} failed out of ${servers.size()} servers"

                    if (failCount > 0) {
                        error "Deployment failed on ${failCount} server(s)"
                    }
                }
            }
        }

        stage('Health Checks') {
            when {
                expression { params.HEALTH_CHECK_URL_PATTERN?.trim() && !params.DRY_RUN }
            }
            steps {
                script {
                    echo "=== Running Health Checks ==="

                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def timeout = params.HEALTH_CHECK_TIMEOUT?.toInteger() ?: 120
                    def healthResults = [:]

                    for (server in servers) {
                        def healthUrl = params.HEALTH_CHECK_URL_PATTERN.replace('{SERVER}', server)
                        echo "Checking health: ${healthUrl} (timeout: ${timeout}s)"

                        try {
                            def healthy = false
                            def elapsed = 0
                            def interval = 5

                            while (!healthy && elapsed < timeout) {
                                try {
                                    def response = sh(
                                        script: "curl -sf -o /dev/null -w '%{http_code}' --connect-timeout 5 --max-time 10 '${healthUrl}'",
                                        returnStdout: true
                                    ).trim()

                                    if (response == '200') {
                                        healthy = true
                                        echo "  ✓ ${server}: Healthy (HTTP ${response}) after ${elapsed}s"
                                    } else {
                                        echo "  ... ${server}: HTTP ${response}, retrying in ${interval}s (${elapsed}s/${timeout}s)"
                                    }
                                } catch (Exception e) {
                                    echo "  ... ${server}: Not ready, retrying in ${interval}s (${elapsed}s/${timeout}s)"
                                }

                                if (!healthy) {
                                    sleep(interval)
                                    elapsed += interval
                                }
                            }

                            if (!healthy) {
                                healthResults[server] = [status: 'UNHEALTHY', message: "Timed out after ${timeout}s"]
                                echo "  ✗ ${server}: UNHEALTHY - timed out after ${timeout}s"
                            } else {
                                healthResults[server] = [status: 'HEALTHY']
                            }
                        } catch (Exception e) {
                            healthResults[server] = [status: 'ERROR', message: e.message]
                            echo "  ✗ ${server}: ERROR - ${e.message}"
                        }
                    }

                    def unhealthyServers = healthResults.findAll { it.value.status != 'HEALTHY' }
                    if (unhealthyServers) {
                        error "Health check failed on: ${unhealthyServers.keySet().join(', ')}"
                    }

                    echo "All servers are healthy!"
                }
            }
        }
    }

    post {
        success {
            echo "=== Deployment Pipeline Completed Successfully ==="
            echo "Artifacts deployed to ${env.SERVER_LIST}"
        }
        failure {
            echo "=== Deployment Pipeline FAILED ==="
            echo "Please check the logs above for details."
            // Optionally send notifications
            script {
                if (!params.DRY_RUN) {
                    echo "ALERT: Production deployment failed! Manual intervention may be required."
                }
            }
        }
        always {
            script {
                echo "=== Cleaning up workspace artifacts ==="
                sh "rm -rf ${ARTIFACTS_DIR}"
            }
        }
    }
}

// ==================== Helper Functions ====================

def extractFilename(String url) {
    if (url.startsWith('s3://')) {
        return url.tokenize('/')[-1]
    }
    def cleanUrl = url.split('\\?')[0] // Remove query parameters
    return cleanUrl.tokenize('/')[-1] ?: "artifact_${System.currentTimeMillis()}"
}

def isArtifactoryUrl(String url) {
    // Check for common Artifactory URL patterns
    return url.contains('/artifactory/') || url.contains('/art/') ||
           (params.ARTIFACTORY_CREDENTIAL_ID?.trim() &&
            (url.contains('jfrog') || url.contains('artifactory')))
}

def downloadFromS3(String s3Url, String targetPath) {
    echo "  Source type: Amazon S3"
    if (params.AWS_CREDENTIAL_ID?.trim()) {
        withCredentials([[$class: 'AmazonWebServicesCredentialsBinding',
                          credentialsId: params.AWS_CREDENTIAL_ID,
                          accessKeyVariable: 'AWS_ACCESS_KEY_ID',
                          secretKeyVariable: 'AWS_SECRET_ACCESS_KEY']]) {
            sh "aws s3 cp '${s3Url}' '${targetPath}'"
        }
    } else {
        // Rely on instance profile or environment credentials
        sh "aws s3 cp '${s3Url}' '${targetPath}'"
    }
}

def downloadFromArtifactory(String url, String targetPath) {
    echo "  Source type: Artifactory"
    if (params.ARTIFACTORY_CREDENTIAL_ID?.trim()) {
        withCredentials([usernamePassword(
            credentialsId: params.ARTIFACTORY_CREDENTIAL_ID,
            usernameVariable: 'ART_USER',
            passwordVariable: 'ART_PASS')]) {
            sh """
                curl -fSL \
                    -u "\${ART_USER}:\${ART_PASS}" \
                    --connect-timeout 30 \
                    --max-time 600 \
                    --retry 3 \
                    --retry-delay 5 \
                    -o '${targetPath}' \
                    '${url}'
            """
        }
    } else {
        downloadFromHttp(url, targetPath)
    }
}

def downloadFromHttp(String url, String targetPath) {
    echo "  Source type: HTTP/HTTPS"
    sh """
        curl -fSL \
            --connect-timeout 30 \
            --max-time 600 \
            --retry 3 \
            --retry-delay 5 \
            -o '${targetPath}' \
            '${url}'
    """
}

def deployToServer(String server, Map deployResults) {
    echo "\n--- Deploying to ${server} ---"

    if (params.DRY_RUN) {
        echo "  [DRY RUN] Would deploy artifacts to ${server}:${params.DEPLOY_PATH}"
        deployResults[server] = [status: 'SUCCESS (DRY RUN)']
        return
    }

    try {
        sshagent(credentials: [params.SSH_CREDENTIAL_ID]) {
            def sshOpts = "-o StrictHostKeyChecking=no -o ConnectTimeout=15"
            def sshTarget = "${params.DEPLOY_USER}@${server}"

            // Test connectivity
            echo "  Testing SSH connectivity to ${server}..."
            sh "ssh ${sshOpts} ${sshTarget} 'echo Connected successfully'"

            // Backup existing artifacts if requested
            if (params.BACKUP_EXISTING) {
                echo "  Backing up existing artifacts on ${server}..."
                sh """
                    ssh ${sshOpts} ${sshTarget} '
                        if [ -d "${params.DEPLOY_PATH}" ] && [ "\$(ls -A ${params.DEPLOY_PATH} 2>/dev/null)" ]; then
                            BACKUP_DIR="${params.DEPLOY_PATH}_backup_${TIMESTAMP}"
                            echo "Creating backup at \${BACKUP_DIR}"
                            cp -a "${params.DEPLOY_PATH}" "\${BACKUP_DIR}"
                            echo "Backup created successfully"
                        else
                            echo "No existing artifacts to backup"
                        fi
                    '
                """
            }

            // Run pre-deploy script if provided
            if (params.PRE_DEPLOY_SCRIPT?.trim()) {
                echo "  Running pre-deploy script on ${server}..."
                sh """
                    ssh ${sshOpts} ${sshTarget} '${params.PRE_DEPLOY_SCRIPT}'
                """
            }

            // Ensure deploy directory exists
            sh """
                ssh ${sshOpts} ${sshTarget} 'mkdir -p "${params.DEPLOY_PATH}"'
            """

            // Upload artifacts
            echo "  Uploading artifacts to ${server}:${params.DEPLOY_PATH}..."
            sh """
                scp ${sshOpts} -r ${ARTIFACTS_DIR}/* ${sshTarget}:"${params.DEPLOY_PATH}/"
            """

            // Verify upload
            echo "  Verifying uploaded artifacts on ${server}..."
            sh """
                ssh ${sshOpts} ${sshTarget} '
                    echo "Files deployed to ${params.DEPLOY_PATH}:"
                    ls -lah "${params.DEPLOY_PATH}/"
                    if [ -f "${params.DEPLOY_PATH}/checksums.sha256" ]; then
                        echo "Verifying checksums..."
                        cd "${params.DEPLOY_PATH}"
                        if command -v sha256sum > /dev/null 2>&1; then
                            sha256sum -c checksums.sha256
                        elif command -v shasum > /dev/null 2>&1; then
                            shasum -a 256 -c checksums.sha256
                        else
                            echo "Warning: No checksum tool available, skipping verification"
                        fi
                    fi
                '
            """

            // Run post-deploy script if provided
            if (params.POST_DEPLOY_SCRIPT?.trim()) {
                echo "  Running post-deploy script on ${server}..."
                sh """
                    ssh ${sshOpts} ${sshTarget} '${params.POST_DEPLOY_SCRIPT}'
                """
            }

            echo "  ✓ Deployment to ${server} completed successfully"
            deployResults[server] = [status: 'SUCCESS']
        }
    } catch (Exception e) {
        echo "  ✗ Deployment to ${server} FAILED: ${e.message}"
        deployResults[server] = [status: 'FAILED', error: e.message]

        // If rolling deploy, attempt rollback on failure
        if (params.ROLLING_DEPLOY && params.BACKUP_EXISTING && !params.DRY_RUN) {
            echo "  Attempting rollback on ${server}..."
            try {
                sshagent(credentials: [params.SSH_CREDENTIAL_ID]) {
                    def sshOpts = "-o StrictHostKeyChecking=no -o ConnectTimeout=15"
                    def sshTarget = "${params.DEPLOY_USER}@${server}"
                    sh """
                        ssh ${sshOpts} ${sshTarget} '
                            BACKUP_DIR="${params.DEPLOY_PATH}_backup_${TIMESTAMP}"
                            if [ -d "\${BACKUP_DIR}" ]; then
                                echo "Rolling back from \${BACKUP_DIR}"
                                rm -rf "${params.DEPLOY_PATH}"
                                mv "\${BACKUP_DIR}" "${params.DEPLOY_PATH}"
                                echo "Rollback completed"
                            else
                                echo "No backup found for rollback"
                            fi
                        '
                    """
                }
                echo "  Rollback on ${server} completed"
            } catch (Exception rollbackEx) {
                echo "  WARNING: Rollback on ${server} also failed: ${rollbackEx.message}"
            }
        }

        if (params.ROLLING_DEPLOY) {
            error "Rolling deployment stopped due to failure on ${server}"
        }
    }
}

def formatFileSize(long bytes) {
    if (bytes < 1024) return "${bytes} B"
    if (bytes < 1024 * 1024) return String.format("%.1f KB", bytes / 1024.0)
    if (bytes < 1024 * 1024 * 1024) return String.format("%.1f MB", bytes / (1024.0 * 1024))
    return String.format("%.1f GB", bytes / (1024.0 * 1024 * 1024))
}